class Solution:
    def checkPalindromeFormation(self, a, b):
        """
        :type a: str
        :type b: str
        :rtype: bool
        """
        def isPalindrome(s):
            return s == s[::-1]

        def helper(s1, s2):
            left = 0
            right = len(s1) - 1

            while left < right:
                if s1[left] != s2[right]:
                    break
                left += 1
                right -= 1

            # Check if either part is palindrome
            return isPalindrome(s1[left:right+1]) or isPalindrome(s2[left:right+1])

        return helper(a, b) or helper(b, a)
